	@Test
	void scalarAdapterPreservesAccessAndEvidenceDiagnostics() {
		StatementPattern factor = pattern("s", PREDICATE, "o");
		Value seedValue = VF.createIRI("urn:seed");
		PlanState prefix = PlanState.initial(BagEstimate.exact(2.0d, "outer"), Set.of("seed"),
				Map.of("seed", Set.of(seedValue)));
		AtomicReference<JoinFactorCostModel.CostContext> observedContext = new AtomicReference<>();
		JoinFactorCostModel costModel = new JoinFactorCostModel() {
			@Override
			public Optional<JoinFactorCostModel.FactorCostEstimate> estimateFactorCost(TupleExpr requestedFactor,
					Set<String> currentlyBoundVars) {
				return Optional.empty();
			}

			@Override
			public Optional<JoinFactorCostModel.FactorCostEstimate> estimateFactorCost(TupleExpr requestedFactor,
					JoinFactorCostModel.CostContext context) {
				observedContext.set(context);
				assertEquals(factor, requestedFactor);
				return Optional.of(new JoinFactorCostModel.FactorCostEstimate(7.0d, 3.0d,
						Map.of("plannedEstimateSource", "lmdb-access-path", "plannedIndexAccessMode",
								"directLookup"),
						Map.of(TelemetryMetricNames.PLANNED_CARDINALITY_CONFIDENCE, 0.75d,
								TelemetryMetricNames.PLANNED_FILTER_EVIDENCE_COUNT, 12.0d,
								"plannedCardinalityQError", 2.0d, "plannedAccessRows", 3.0d),
						true, true, 5, 2, 3.0d, true, true));
			}
		};

		ScalarFactorTransitionEstimator estimator = new ScalarFactorTransitionEstimator(costModel);
		TransitionEstimate transition = estimator.transition(prefix, AccessPathCandidate.forFactor(factor))
				.orElseThrow();

		assertEquals(Set.of("seed", "s", "o"), transition.nextState().boundVars());
		assertEquals(Set.of(seedValue), transition.nextState().finiteBindingValues().get("seed"));
		assertEquals(1, transition.nextState().prefixFactors().size());
		assertEquals(factor, transition.nextState().prefixFactors().get(0));
		assertTrue(transition.factorCostEstimate().hasPhysicalAccessPath());
		assertTrue(transition.factorCostEstimate().isDirectLookup());
		assertEquals(5, transition.factorCostEstimate().getLookupComponentMask());
		assertEquals(2, transition.factorCostEstimate().getMissingLookupComponentMask());
		assertEquals(3.0d, transition.factorCostEstimate().getAccessRowsBeforeFilter(), 1.0e-9d);
		assertEquals(0.75d, transition.planCost().confidence(), 1.0e-9d);
		assertEquals(12.0d, transition.planCost().evidenceCount(), 1.0e-9d);
		assertEquals(2.0d, transition.planCost().rowQErrorMax(), 1.0e-9d);
		assertEquals("lmdb-access-path", transition.stringDiagnostics().get("plannedEstimateSource"));
		assertEquals(3.0d, transition.doubleDiagnostics().get("plannedAccessRows"), 1.0e-9d);
		assertEquals(Set.of("seed"), observedContext.get().getCurrentlyBoundVars());
		assertEquals(2.0d, observedContext.get().getOuterPrefixRows(), 1.0e-9d);
		assertEquals(Set.of(seedValue), observedContext.get().getFiniteBindingValues().get("seed"));
	}

	@Test
	void runtimeVarsExcludeConstantAndInternalVars() {
		StatementPattern constantObject = new StatementPattern(new Var("s"), new Var("p", PREDICATE),
				new Var("fixed", VF.createLiteral("literal")));
		AccessPathCandidate constantCandidate = AccessPathCandidate.forFactor(constantObject);

		assertEquals(Set.of("s"), constantCandidate.runtimeVars());
		assertFalse(constantCandidate.runtimeVars().contains("p"));
		assertFalse(constantCandidate.runtimeVars().contains("fixed"));

		StatementPattern internalSubject = new StatementPattern(new Var("_const_internal"), new Var("p", PREDICATE),
				new Var("o"));
		AccessPathCandidate internalCandidate = AccessPathCandidate.forFactor(internalSubject);

		assertEquals(Set.of("o"), internalCandidate.runtimeVars());
		assertFalse(internalCandidate.runtimeVars().contains("_const_internal"));
	}

